function clean(v) {
  return String(v || '').replace(/\s+/g, ' ').trim();
}

return items.map(({ json }) => {
  const url = json.link || json.guid || json.url;
  const title = clean(json.title);
  const text = clean(json.content || json.contentSnippet || json.description || json.text || title);
  if (!url || !title) return null;

  const joined = `${title} ${text}`;
  const locale = /[а-яё]/i.test(joined) ? 'ru' : 'en';

  return {
    json: {
      externalId: String(json.guid || url).slice(0, 500),
      sourcePlatform: 'rss',
      sourceName: clean(json.feedTitle || json.creator || json.author || 'RSS / News').slice(0, 180),
      sourceUrl: String(url),
      canonicalUrl: String(url).split('#')[0],
      author: json.creator || json.author || null,
      locale,
      title: title.slice(0, 500),
      rawContent: text || title,
      imageUrl: json.imageUrl || json.enclosure?.url || null,
      publishedAt: json.isoDate || json.pubDate || null,
      category: 'ai',
      sourceScore: 12
    }
  };
}).filter(Boolean);

const queries = String("AI agents,robotics,humanoid robots,future tech,automation,OpenAI,Claude,Gemini" || 'AI agents,robotics,humanoid robots,future tech,automation,OpenAI,Claude,Gemini')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

const after = Math.floor((Date.now() - 48 * 60 * 60 * 1000) / 1000);

return queries.map(query => ({
  json: {
    query,
    after,
    hitsPerPage: 25
  }
}));

const hits = $json.hits || [];
const blockShowHN = true;

return hits
  .filter(hit => hit && hit.title && (hit.url || hit.objectID))
  .filter(hit => {
    if (!blockShowHN) return true;

    const title = String(hit.title || '').trim().toLowerCase();

    // Убираем Show HN:, Show HN -, Show HN –
    return !/^show hn\s*[:\-–]/i.test(title);
  })
  .slice(0, 20)
  .map(hit => {
    const discussion = 'https://news.ycombinator.com/item?id=' + hit.objectID;
    const sourceUrl = hit.url || discussion;
    const points = Number(hit.points || 0);
    const comments = Number(hit.num_comments || 0);

    const raw = [
      hit.title,
      hit.story_text || '',
      'HN points: ' + points,
      'HN comments: ' + comments,
      'Discussion: ' + discussion
    ].filter(Boolean).join('\n');

    return {
      json: {
        externalId: 'hn:' + hit.objectID,
        sourcePlatform: 'manual',
        sourceName: 'Hacker News',
        sourceUrl,
        canonicalUrl: String(sourceUrl).split('#')[0],
        author: hit.author || null,
        locale: 'en',
        title: String(hit.title).slice(0, 500),
        rawContent: raw,
        imageUrl: null,
        publishedAt: hit.created_at || null,
        category: 'ai',
        hnPoints: points,
        hnComments: comments,
        discussionUrl: discussion,

        // Сниженный вес Hacker News
        sourceScore: 4 + Math.min(10, comments * 0.2) + Math.min(5, points * 0.03)
      }
    };
  });

const queries = String("AI agents future of work,humanoid robots,AI robotics debate,future tech AI" || 'AI agents future of work,humanoid robots,AI robotics debate,future tech AI')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

return queries.map(query => ({ json: { query } }));

const list = $json.items || [];

return list.map(item => {
  const videoId = item.id?.videoId;
  if (!videoId) return null;

  const s = item.snippet || {};
  const url = 'https://www.youtube.com/watch?v=' + videoId;
  const title = String(s.title || '').replace(/\s+/g, ' ').trim();
  if (!title) return null;

  const raw = [
    title,
    s.description || '',
    'Channel: ' + (s.channelTitle || 'YouTube')
  ].join('\n');

  return {
    json: {
      externalId: 'youtube:' + videoId,
      sourcePlatform: 'manual',
      sourceName: 'YouTube',
      sourceUrl: url,
      canonicalUrl: url,
      author: s.channelTitle || null,
      locale: 'en',
      title: title.slice(0, 500),
      rawContent: raw,
      imageUrl: s.thumbnails?.high?.url || s.thumbnails?.medium?.url || null,
      publishedAt: s.publishedAt || null,
      category: 'ai',
      sourceScore: 7
    }
  };
}).filter(Boolean);

function clean(v) {
  return String(v || '').replace(/\s+/g, ' ').trim();
}

function norm(v) {
  return clean(v)
    .toLowerCase()
    .replace(/https?:\/\/(www\.)?/g, '')
    .replace(/[^a-zа-яё0-9\s]/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function escapeHtml(v) {
  return String(v || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function ageHours(publishedAt) {
  if (!publishedAt) return 24;
  const t = new Date(publishedAt).getTime();
  if (!Number.isFinite(t)) return 24;
  return Math.max(0, (Date.now() - t) / 36e5);
}

function freshnessScore(hours) {
  if (hours <= 3) return 30;
  if (hours <= 6) return 27;
  if (hours <= 12) return 23;
  if (hours <= 24) return 18;
  if (hours <= 48) return 12;
  return 4;
}

function domainOf(url) {
  try { return new URL(url).hostname.replace(/^www\./, ''); } catch { return ''; }
}

const authorityDomains = [
  'openai.com','anthropic.com','deepmind.google','googleblog.com','microsoft.com',
  'nvidia.com','meta.com','tesla.com','figure.ai','unitree.com','reuters.com',
  'bloomberg.com','theverge.com','techcrunch.com','wired.com','technologyreview.com',
  'arstechnica.com','semianalysis.com','news.ycombinator.com'
];

const relevanceTerms = [
  'ai','artificial intelligence','agent','agents','robot','robotics','humanoid',
  'future tech','automation','openai','anthropic','claude','chatgpt','gemini',
  'deepmind','nvidia','tesla bot','figure','unitree','agi','coding agent',
  'модель','робот','робототехника','искусственный интеллект','агент'
];

const debateTerms = [
  'lawsuit','ban','safety','regulation','controversy','risk','replace','jobs',
  'privacy','security','censorship','bubble','hype','layoffs','опасность','риск',
  'регулятор','запрет','заменит','увольнения','цензура','пузырь'
];

const rowsRaw = items.map(i => i.json).filter(r => r && r.title && r.sourceUrl);

const byKey = new Map();

for (const row of rowsRaw) {
  const titleNorm = norm(row.title);
  const canonical = clean(row.canonicalUrl || row.sourceUrl).split('#')[0];
  const key = canonical || titleNorm.split(' ').slice(0, 10).join('-');

  const blob = norm(`${row.title} ${row.rawContent || ''}`);
  const hours = ageHours(row.publishedAt);
  const domain = domainOf(row.sourceUrl);
  const authority = authorityDomains.some(d => domain.includes(d)) ? 18 : 5;
  const relevance = relevanceTerms.reduce((sum, term) => sum + (blob.includes(norm(term)) ? 4 : 0), 0);
  const debate = debateTerms.reduce((sum, term) => sum + (blob.includes(norm(term)) ? 3 : 0), 0);
  const platformScore = Number(row.sourceScore || 0);
  const scoreRaw = freshnessScore(hours) + authority + relevance + debate + platformScore;
  const score = Math.max(1, Math.min(10, Math.round((scoreRaw / 10) * 10) / 10));

  const enriched = {
    ...row,
    score,
    scoreRaw,
    ageHours: Math.round(hours * 10) / 10,
    domain,
    reasons: [
      `freshness:${freshnessScore(hours)}`,
      `authority:${authority}`,
      `relevance:${relevance}`,
      `debate:${debate}`,
      `source:${Math.round(platformScore * 10) / 10}`
    ]
  };

  if (!byKey.has(key) || byKey.get(key).scoreRaw < enriched.scoreRaw) {
    byKey.set(key, enriched);
  }
}

const top = [...byKey.values()]
  .sort((a, b) => b.scoreRaw - a.scoreRaw)
  .slice(0, 10)
  .map((row, index) => ({
    ...row,
    rank: index + 1
  }));

if (!top.length) {
  return [{
    json: {
      payload: {
        chat_id: "-1004312670393",
        message_thread_id: Number("2" || 0) || undefined,
        text: 'AI News Radar: новых кандидатов не найдено.',
        parse_mode: 'HTML'
      }
    }
  }];
}

const radarId = `r${Date.now().toString(36)}`;

const store = $getWorkflowStaticData('global');

store.radars = store.radars || {};
store.latestRadar = {
  id: radarId,
  createdAt: new Date().toISOString(),
  top
};

store.radars[radarId] = store.latestRadar;
store.latestRadarId = radarId;

// cleanup old radars
const keys = Object.keys(store.radars);
if (keys.length > 30) {
  keys
    .sort((a,b) => String(store.radars[a].createdAt).localeCompare(String(store.radars[b].createdAt)))
    .slice(0, keys.length - 30)
    .forEach(k => delete store.radars[k]);
}

const lines = [
  '<b>🧠 Den’s Workspace AI News Radar — TOP 10</b>',
  '',
  'Выбери новость кнопкой или ответь цифрой <b>1–10</b>.',
  '',
  ...top.map(row => {
    const title = escapeHtml(row.title);
    const url = escapeHtml(row.sourceUrl);
    const source = escapeHtml(row.sourceName || row.domain || 'source');
    const age = row.ageHours <= 24 ? `${row.ageHours}h` : `${Math.round(row.ageHours / 24)}d`;
    return `${row.rank}) 🔥 <b>${row.score}/10</b> · <a href="${url}">${title}</a>\nИсточник: ${source} · ${age}`;
  })
];

const buttons = top.map(row => ({
  text: `${row.rank}`,
  callback_data: `select:${radarId}:${row.rank}`
}));

const inline_keyboard = [
  buttons.slice(0, 5),
  buttons.slice(5, 10)
].filter(row => row.length);

const payload = {
  chat_id: "-1004312670393",
  message_thread_id: Number("2" || 0) || undefined,
  text: lines.join('\n\n'),
  parse_mode: 'HTML',
  disable_web_page_preview: true,
  reply_markup: { inline_keyboard }
};

Object.keys(payload).forEach(key => payload[key] === undefined && delete payload[key]);

return [{ json: { radarId, top, payload } }];

const store = $getWorkflowStaticData('global');
const callback = $json.callback_query;
const message = $json.message;

let action = '';
let radarId = '';
let rank = 0;
let callbackQueryId = null;
let chatId = '';
let messageThreadId = '';
let callbackMessageText = '';
let callbackMessageEntities = [];
let fromId = '';
let fromUsername = '';

if (callback?.data) {
  const parts = String(callback.data).split(':');
  action = parts[0] || '';
  radarId = parts[1] || store.latestRadarId || 'latest';
  rank = Number(parts[2] || 0);
  callbackQueryId = callback.id || null;
  const cbMessage = callback.message || {};
  chatId = cbMessage.chat?.id || "-1004312670393";
  messageThreadId = cbMessage.message_thread_id || "2";
  callbackMessageText = cbMessage.text || cbMessage.caption || '';
  callbackMessageEntities = cbMessage.entities || cbMessage.caption_entities || [];
  fromId = callback.from?.id || '';
  fromUsername = callback.from?.username || '';
} else if (message?.text) {
  const text = String(message.text).trim();
  const numberMatch = text.match(/^(10|[1-9])$/);
  if (numberMatch) {
    action = 'select';
    radarId = store.latestRadarId || 'latest';
    rank = Number(numberMatch[1]);
  } else if (/^(да|yes|y|publish|site|✅)/i.test(text)) {
    action = 'publish_site';
  } else if (/^(нет|no|n|skip|🚫)/i.test(text)) {
    action = 'skip_site';
  }
  chatId = message.chat?.id || "-1004312670393";
  messageThreadId = message.message_thread_id || "2";
  fromId = message.from?.id || '';
  fromUsername = message.from?.username || '';
}

return [{
  json: {
    action,
    radarId,
    rank,
    callbackQueryId,
    chatId,
    messageThreadId,
    callbackMessageText,
    callbackMessageEntities,
    fromId,
    fromUsername,
  }
}];

const data = $json;
const store = $getWorkflowStaticData('global');

function clean(v) {
  return String(v || '').replace(/\s+/g, ' ').trim();
}

function cleanUrl(v) {
  try {
    const url = new URL(String(v));
    url.hash = '';
    for (const key of ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'fbclid', 'gclid']) {
      url.searchParams.delete(key);
    }
    return url.toString();
  } catch (e) {
    return String(v || '').trim();
  }
}

function domainFromUrl(v) {
  try {
    return new URL(v).hostname.replace(/^www\./, '');
  } catch (e) {
    return '';
  }
}

function parseSelectedFromTelegramMessage(input) {
  const text = String(input.callbackMessageText || '');
  const rank = Number(input.rank || 0);
  if (!text || !rank) return null;

  const lines = text.split(/\r?\n/);
  let offset = 0;
  let lineStart = 0;
  let rankLine = '';
  let rankLineIndex = -1;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i] || '';
    if (new RegExp('^' + rank + '\\)').test(line.trim())) {
      lineStart = offset;
      rankLine = line;
      rankLineIndex = i;
      break;
    }
    offset += line.length + 1;
  }

  if (!rankLine) return null;

  const lineEnd = lineStart + rankLine.length;
  const entities = Array.isArray(input.callbackMessageEntities) ? input.callbackMessageEntities : [];
  const linkEntity = entities.find(entity => {
    const entityOffset = Number(entity.offset || 0);
    return entity.type === 'text_link' && entity.url && entityOffset >= lineStart && entityOffset <= lineEnd;
  });

  const urlMatch = rankLine.match(/https?:\/\/\S+/);
  const sourceUrl = cleanUrl(linkEntity?.url || urlMatch?.[0] || '');
  if (!sourceUrl) return null;

  let title = clean(rankLine)
    .replace(/^\d+\)\s*/, '')
    .replace(/^🔥\s*/, '')
    .replace(/^\d+(?:\.\d+)?\/10\s*[·-]\s*/, '')
    .replace(/\s*\(https?:\/\/[^)]+\)\s*$/, '')
    .trim();

  if (!title) title = sourceUrl;

  let sourceLine = '';
  for (let i = rankLineIndex + 1; i < Math.min(lines.length, rankLineIndex + 4); i++) {
    const candidate = clean(lines[i]);
    if (/^(Источник|Source):/i.test(candidate)) {
      sourceLine = candidate;
      break;
    }
  }

  const sourceClean = sourceLine.replace(/^(Источник|Source):\s*/i, '');
  const sourceName = clean(sourceClean.split('·')[0]) || domainFromUrl(sourceUrl) || 'Telegram selection';

  return {
    rank,
    title,
    sourceUrl,
    canonicalUrl: sourceUrl,
    sourceName,
    author: sourceName,
    rawContent: title,
    imageUrl: null,
    publishedAt: null,
    fingerprint: sourceUrl,
    score: null,
    scoreRaw: null,
    sourceScore: 0,
    ageHours: null,
    domain: domainFromUrl(sourceUrl),
    reasons: ['Recovered from Telegram TOP-10 message because n8n staticData did not contain this radarId'],
  };
}

store.radars = store.radars || {};

let radar = store.radars?.[data.radarId];
let selected = null;

if (radar && Array.isArray(radar.top)) {
  selected = radar.top.find(item => Number(item.rank) === Number(data.rank));
}

if (!selected) {
  selected = parseSelectedFromTelegramMessage(data);
  if (selected) {
    const recoveredId = data.radarId || ('recovered-' + Date.now().toString(36));
    radar = {
      id: recoveredId,
      top: [selected],
      recoveredFromTelegramMessage: true,
      recoveredAt: new Date().toISOString(),
    };
    store.radars[recoveredId] = radar;
    if (data.radarId) store.radars[data.radarId] = radar;
  }
}

if (!selected) {
  const available = Object.keys(store.radars || {}).join(', ') || 'none';
  throw new Error(
    'Radar not found or selected rank missing: radar=' + data.radarId + ', rank=' + data.rank + '. Available radars: ' + available + '. ' +
    'This usually means Telegram handled a button from another workflow copy or old execution. Run TOP-10 again from the active workflow and click the new message.'
  );
}

return [{
  json: {
    ...data,
    radarId: radar?.id || data.radarId,
    selected,
  }
}];

options.systemMessage:
Ты — редактор Den's Workspace.

Задача:
Сделать короткий Telegram-пост и image prompt по выбранной новости про AI / Robotics / Future Tech.

Это НЕ рерайт новости.
Это авторский комментарий: почему событие важно, что в нем спорного, куда это может вести, какой в этом сигнал для будущего.

Стиль:
- русский язык;
- живой, умный, немного предпринимательский;
- можно от первого лица, если уместно;
- без дешевого кликбейта;
- без воды и канцелярита;
- короткие абзацы;
- можно 1-3 эмодзи, но не перегружать;
- не выдумывать факты, цифры, цитаты;
- отделять факт новости от мнения;
- обязательно оставить ощущение "это мнение автора, а не переписанная новость".

Ограничения:
- Telegram text: 700–1200 символов.
- В тексте обязательно должна быть мысль "почему это важно".
- Не вставляй URL в текст: workflow добавит источник отдельно.
- Используй HTML только для <b>...</b>. Не используй markdown **.

Image prompt:
- английский язык;
- реалистичная премиальная editorial-сцена по теме AI / robotics / future tech;
- без букв, текста, логотипов, интерфейсных надписей;
- стиль: cinematic, photorealistic, premium tech editorial.

Верни строго такой формат:

[TEXT]
...готовый Telegram-комментарий...
[/TEXT]

[IMAGE]
...english image prompt...
[/IMAGE]

[QUESTION]
...короткий вопрос: публикуем ли на сайт как авторское мнение?...
[/QUESTION]

