const original = $('Get Selected News').first().json;

const rawOutput = String(
  $json.output ||
  $json.text ||
  $json.response ||
  $json.message ||
  JSON.stringify($json)
);

// Parse [TEXT] / [IMAGE] / [QUESTION] safely
const textMatch = rawOutput.match(/\[TEXT\]([\s\S]*?)\[\/TEXT\]/i);
const imgMatch = rawOutput.match(/\[IMAGE\]([\s\S]*?)\[\/IMAGE\]/i);
const questionMatch = rawOutput.match(/\[QUESTION\]([\s\S]*?)\[\/QUESTION\]/i);

let text = (textMatch ? textMatch[1] : rawOutput).trim();
let basePrompt = (imgMatch ? imgMatch[1] : `${original.selected.title}, AI future technology editorial scene`).trim();
let siteQuestion = (questionMatch ? questionMatch[1] : 'Будем публиковать на сайт как авторское мнение?').trim();

function clean(v) {
  return String(v || '')
    .replace(/\r/g, '')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

text = clean(text)
  .replace(/```html/gi, '')
  .replace(/```/g, '')
  .trim();

siteQuestion = clean(siteQuestion).slice(0, 500) || 'Будем публиковать на сайт как авторское мнение?';

// Safe Telegram caption limit
const MAX_CAPTION = 950;
if (text.length > MAX_CAPTION) {
  let cut = text.slice(0, MAX_CAPTION);
  const sentenceCut = Math.max(cut.lastIndexOf('.'), cut.lastIndexOf('!'), cut.lastIndexOf('?'));
  if (sentenceCut > 500) cut = cut.slice(0, sentenceCut + 1);
  else {
    const spaceCut = cut.lastIndexOf(' ');
    if (spaceCut > 400) cut = cut.slice(0, spaceCut);
  }
  text = cut.trim();
}

// Image prompt anti-garbage cleanup, borrowed from News_Generation_PRO logic
basePrompt = clean(basePrompt)
  .replace(/\s*,\s*/g, ', ')
  .trim();

const banned = [
  'abstract',
  'digital streams',
  'symbols',
  'holograms',
  'concept',
  'cyberpunk',
  'floating screens',
  'glowing lines',
  'text',
  'letters',
  'typography',
  'logo',
  'watermark'
];

for (const w of banned) {
  const re = new RegExp(`\\b${w.replace(/[-/\\^$*+?.()|[\]{}]/g, '\\$&')}\\b`, 'ig');
  basePrompt = basePrompt.replace(re, '');
}

basePrompt = basePrompt
  .replace(/\s{2,}/g, ' ')
  .replace(/,\s*,/g, ',')
  .trim();

const angles = [
  'macro photography, extreme close up',
  'isometric 3D view, elevated 45 degrees',
  'low angle shot from below, dramatic',
  'bird’s-eye view, looking straight down',
  'over-the-shoulder perspective',
  'first-person point of view',
  'wide shot from a corner of a premium AI research lab'
];

const lighting = [
  'cinematic lighting, strong contrast',
  'soft diffused natural light from window',
  'moody dark shadows, single desk lamp',
  'blue hour, twilight, dim',
  'premium editorial studio lighting'
];

const mood = [
  'photorealistic, editorial technology photo',
  'hyperrealistic, premium quality',
  'documentary style',
  'clean corporate realism'
];

const extra = [
  'reflection on a polished table',
  'blurred city lights in background',
  'a coffee cup with steam',
  'an old analog clock on the wall',
  'dust particles in the light beam',
  'subtle futuristic lab atmosphere'
];

const rand = (arr) => arr[Math.floor(Math.random() * arr.length)];

let finalPrompt = [
  basePrompt || 'premium AI research lab, robotics and future technology, realistic editorial scene',
  rand(angles),
  rand(lighting),
  rand(mood),
  `additional detail: ${rand(extra)}`,
  'cinematic lighting, photorealistic, premium tech editorial photo, no text, no letters, no typography, no logo, no watermark'
]
  .join(', ')
  .replace(/\s{2,}/g, ' ')
  .replace(/,\s*,/g, ',')
  .trim();

if (finalPrompt.length > 1000) {
  finalPrompt = finalPrompt.slice(0, 1000).trim();
  const lastComma = finalPrompt.lastIndexOf(',');
  if (lastComma > 700) finalPrompt = finalPrompt.slice(0, lastComma).trim();
  finalPrompt += ', no text, no letters, no typography, no logo, no watermark';
}

return [{
  json: {
    ...original,
    ai: {
      telegramCaption: text,
      imagePrompt: finalPrompt,
      siteQuestion
    }
  }
}];

const enriched = $('Parse AI Telegram Commentary').first().json;
const input = $input.first();
const binary = input.binary || {};

function stripBadHtml(v) {
  return String(v || '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<\/?(?!b\b|\/b\b)[^>]+>/gi, '')
    .trim();
}

const sourceUrl = enriched.selected.sourceUrl;
let caption = stripBadHtml(enriched.ai.telegramCaption);

if (!caption.includes(sourceUrl)) {
  caption += `\n\nИсточник: ${sourceUrl}`;
}

caption = caption.slice(0, 1000);

const payload = {
  chat_id: "-1004312670393",
  message_thread_id: Number("2" || 0) || undefined,
  caption,
  parse_mode: 'HTML',
  reply_markup: {
    inline_keyboard: [[
      { text: 'Открыть источник', url: sourceUrl }
    ]]
