function clean(v) {
  return String(v || '')
    .replace(/\r/g, '')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{4,}/g, '\n\n')
    .trim();
}

function section(name) {
  const re = new RegExp(`\\[${name}\\]([\\s\\S]*?)\\[\\/${name}\\]`, 'i');
  const match = raw.match(re);
  return match ? clean(match[1]) : '';
}

function extractJson(text) {
  try {
    const first = text.indexOf('{');
    const last = text.lastIndexOf('}');
    if (first === -1 || last === -1 || last <= first) return {};
    let s = text.slice(first, last + 1);

    // repair raw newlines inside JSON strings
    let result = '';
    let inString = false;
    let escaped = false;

    for (let i = 0; i < s.length; i++) {
      const ch = s[i];

      if (escaped) {
        result += ch;
        escaped = false;
        continue;
      }

      if (ch === '\\') {
        result += ch;
        escaped = true;
        continue;
      }

      if (ch === '"') {
        inString = !inString;
        result += ch;
        continue;
      }

      if (inString && ch === '\n') {
        result += '\\n';
        continue;
      }

      if (inString && ch === '\r') {
        result += '\\r';
        continue;
      }

      if (inString && ch === '\t') {
        result += '\\t';
        continue;
      }

      result += ch;
    }

    return JSON.parse(result);
  } catch (e) {
    return {};
  }
}

function cleanUrl(value) {
  return String(value || '').split('#')[0].trim();
}

